<template>
  <div class="l-note" :class="{ 'sidebar-open': isSidebar }">
    <div class="l-note__hd">
      <div class="hd">
        <div class="hd__wp">
          <div class="logo u-imgfix:in"></div>
          <div class="menu">
            <div class="toggle" @click="sidebarToggle">
              <div class="toggle__bar"><span></span><span></span><span></span></div>
            </div>
          </div>
        </div>
      </div>
    </div>

    <div class="l-note__ctr">

      <div class="l-note__sidebar">
        <div class="sidebar">
          <div class="search">
            <div class="c-fm:noteSearch">
              <input type="text" placeholder="Search ..." id="sidebarSearch" class="c-fm__input"
                v-model.trim="searchTerm">
              <label for="#sidebarSearch" class="c-fm__icon" :class="{ 'is-ing': isSearchIcon }"
                @click="clearSearch"></label>
            </div>
          </div>

          <ul class="list">
            <li class="list__item" v-for="val in filteredItems" :key="val">
              <div class="list__link" @click="changeDetail(val)" :class="{'is-active' : val.name === activeName}">
                <div class="list__link-icon"></div>
                <div class="list__link-name">{{ val.name }}</div>
              </div>
            </li>
          </ul>

          <div class="community">
            <div class="community__item" v-for="val in comunity" :key="val">
              <a :href="val.href" target="_blank" rel="noopener noreferrer" class="community__link"
                :class="'is-' + val.icon"></a>
            </div>
          </div>
        </div>
      </div>

      <div class="l-note__main">

        <div class="l-note__view">
          <div class="l-edit" v-html="markdownContent" v-if="markdownContent !== undefined"></div>
          <router-view v-else-if="isDetailView && markdownContent === undefined"></router-view>
          <div class="e-tips" v-else>📄 Note Page ...</div>
        </div>

        <div class="l-note__ft">
          <div class="copyright">
            <div class="copyright__text">Copyright© JhuangPing 2019 - All. <span>Design by JhuangPing</span></div>
          </div>
        </div>

        <div class="btn-group">
          <div class="c-btn:gotop" @click="toTop">
            <div class="c-btn__icon"></div>
          </div>
        </div>
      </div>

    </div>

    <div class="el-mask" @click="sidebarToggle"></div>
  </div>
</template>

<script setup>
import { defineOptions, ref, defineProps, onMounted, toRaw, computed } from 'vue'
import { useRouter } from "vue-router"
import markdownIt from 'markdown-it'
// layout setting
import { getComunity } from '@api/note/getComunity'
// javscript
import { getDevice } from "@utils/getDevice"
import { setupScroll } from './use/useScroll'

defineOptions({ name: 'LayoutNote' })

const props = defineProps({
  type: String,
  buildSidebar: Object
})
const router = useRouter()
const device = new getDevice(1366)

// Comunity
const comunity = ref(getComunity().list)

const isSidebar = ref(true)

const sidebarToggle = () => {
  isSidebar.value = !isSidebar.value
}

// 側邊欄
const newSidebar = ref([])
const activeName = ref('')
const setSidebar = () => {
  newSidebar.value = toRaw(props.buildSidebar)
  .filter(item => item.isShow === 1)
}

const activeSidebar = (name) => {
  activeName.value = name
}

// 搜詢
const searchTerm = ref('')
const filteredItems = computed(() => {
  if (searchTerm.value.startsWith("tag:")) {
    const keyword = searchTerm.value.slice(4).toLowerCase();
    return props.buildSidebar.filter(item =>
      item.tags.toLowerCase().includes(keyword)
    )
  }

  return searchTerm.value !== '' ? 
    props.buildSidebar.filter(item =>
      item.name.toLowerCase().includes(searchTerm.value.toLowerCase())
    ) 
    : newSidebar.value
})
const isSearchIcon = computed(() => {
  return searchTerm.value !== ''
})
const clearSearch = () => {
  searchTerm.value = ''
}

// 內容設定
const isDetailView = ref(false)
const markdownContent = ref()

// 清空內容
const clearDetail = () => {
  isDetailView.value = false
  markdownContent.value = undefined
}

const getDetail = async  (val) =>{
  try {
    // 使用 fetch 加载 Markdown 文件
    const response = await fetch(`./file-notes/${toRaw(props.type)}/${val.url}.${val.type}`)
    if (!response.ok) {
      throw new Error(`Failed to load Markdown file: ${response.statusText}`)
    }
    const rawMarkdown = await response.text(); // 获取 Markdown 文件内容

    // 使用 markdown-it 渲染 Markdown 内容
    const md = markdownIt()
    if (val.type === 'md') {
      markdownContent.value = md.render(rawMarkdown)
    } else {
      markdownContent.value = rawMarkdown
    }
  } catch (error) {
    console.error('Error loading Markdown file:', error)
    markdownContent.value = '<div class="error-tips">⚠️ Error loading content ?!</div>'
  }
}

// 更換內容
const changeDetail = async (val) => {
  activeSidebar(val.name)

  device.getWindowSize().isSmallScreen ? sidebarToggle() : ''

  switch (val.type) {
    case 'md':
      getDetail(val)

      break

    case 'html':
      getDetail(val)

      break

    case 'vue':
      clearDetail()
      isDetailView.value = true
      router.push({ name: val.url })

      break

    default:
      clearDetail()

      break
  }
}

const toTop = () => {
  document.querySelector('.l-note__view').scrollTo({
    top: 0,
    behavior: 'smooth',
  })
}

const { initScroll } = setupScroll()
onMounted(() => {
  setSidebar();
  initScroll();
})
</script>

<style lang="sass" scoped>
@import @sass/init
@import @sass/helpers

@import ./style
@import ./style/hackmd
@import ./style/edit
</style>
