export const setupScroll = () => {
  let viewHeight = 0;
  let viewElement;

  const calculateDimensions = () => {
    viewElement = document.querySelector('.l-note__view');
    viewHeight = viewElement.scrollHeight;
  };

  const onScroll = () => {
    const scrollPosition = viewElement.scrollTop; // 正確取得滾動容器的滾動位置
    const gotopElement = document.querySelector('.c-btn\\:gotop');

    if (!gotopElement) {
      console.error('回頂部按鈕未找到，請檢查 class 是否正確');
      return;
    }

    if (scrollPosition > 0) {
      gotopElement.classList.add('is-show'); // 顯示按鈕
      if (scrollPosition + viewElement.clientHeight >= viewHeight) {
        gotopElement.classList.remove('is-move');
      } else {
        gotopElement.classList.add('is-move');
      }
    } else {
      gotopElement.classList.remove('is-show'); // 隱藏按鈕
    }
  };

  const initScroll = () => {
    calculateDimensions();
    window.addEventListener('resize', calculateDimensions); // 重新計算高度
    viewElement.addEventListener('scroll', () => {
      requestAnimationFrame(onScroll); // 使用 requestAnimationFrame 優化性能
    });
  };

  return { initScroll };
};
